import { useState, useEffect } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { useAuth } from "@/hooks/useAuth";
import { useToast } from "@/hooks/use-toast";
import { BottomNavigation } from "@/components/ui/bottom-navigation";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Skeleton } from "@/components/ui/skeleton";
import { Badge } from "@/components/ui/badge";
import { Link } from "wouter";
import { apiRequest } from "@/lib/queryClient";
import ContextualHelp from "@/components/ContextualHelp";

interface USWCalculation {
  subscriptionTotal: number;
  mulahFee: number;
  totalCharge: number;
  isPremium: boolean;
  canRun: boolean;
  message: string;
  nextRunDate: string;
  breakdown: {
    monthly: number;
    yearly: number;
    weekly: number;
    subscriptionCount: number;
  };
}

export default function USW() {
  const { user, isAuthenticated, isLoading: authLoading } = useAuth();
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [showRunModal, setShowRunModal] = useState(false);
  const [showCelebration, setShowCelebration] = useState(false);

  // Redirect to home if not authenticated
  useEffect(() => {
    if (!authLoading && !isAuthenticated) {
      toast({
        title: "Unauthorized",
        description: "You are logged out. Logging in again...",
        variant: "destructive",
      });
      setTimeout(() => {
        window.location.href = "/api/login";
      }, 500);
      return;
    }
  }, [isAuthenticated, authLoading, toast]);

  const { data: uswCalculation, isLoading: calculationLoading } = useQuery<USWCalculation>({
    queryKey: ["/api/usw/calculate"],
    enabled: isAuthenticated,
  });

  const runUSWMutation = useMutation({
    mutationFn: async () => {
      const response = await apiRequest("POST", "/api/usw/run");
      return await response.json();
    },
    onSuccess: (data: any) => {
      setShowRunModal(false);

      // Show celebration for first-time USW users!
      if (data.isFirstRun) {
        setShowCelebration(true);
        // Auto-hide celebration after 5 seconds
        setTimeout(() => setShowCelebration(false), 5000);
      }

      toast({
        title: data.isFirstRun ? "🎉 Welcome to USW!" : "USW Run Successful!",
        description: data.isFirstRun 
          ? "Congratulations! You're now a USW member. Your financial life just got simpler!" 
          : (data.message || "USW executed successfully"),
      });
      queryClient.invalidateQueries({ queryKey: ["/api/usw/calculate"] });
      queryClient.invalidateQueries({ queryKey: ["/api/auth/user"] });
    },
    onError: (error: any) => {
      toast({
        title: "USW Run Failed",
        description: error.message || "Failed to run USW",
        variant: "destructive",
      });
    },
  });

  if (authLoading || calculationLoading) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-slate-50 via-blue-50 to-indigo-50">
        <div className="p-6">
          <Skeleton className="h-8 w-48 mb-6" />
          <div className="space-y-4">
            {[1, 2, 3].map((i) => (
              <Skeleton key={i} className="h-32 w-full" />
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <>
      {/* Header */}
      <div className="glass-effect sticky top-0 z-50 border-b border-white/20 bg-gradient-to-br from-slate-50 via-blue-50 to-indigo-50">
        <div className="p-6">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-2xl font-bold bg-gradient-to-r from-emerald-600 to-teal-600 bg-clip-text text-transparent">
                🔗 Unified Subscription Wallet
              </h1>
              <p className="text-gray-600 text-sm mt-1">One payment. All subscriptions. Perfect timing.</p>
            </div>
            <Badge variant={uswCalculation?.isPremium ? "default" : "secondary"}>
              {uswCalculation?.isPremium ? "Premium" : "Free"}
            </Badge>
          </div>
        </div>
      </div>

      <div className="bg-gradient-to-br from-slate-50 via-blue-50 to-indigo-50 p-6 pb-32 space-y-6">
        {/* USW Overview Card */}
        <div className="mulah-primary rounded-3xl p-8 text-white mb-8 card-hover modern-shadow">
          <div className="text-center">
            <div className="text-6xl mb-4 animate-bounce-slow">💰</div>
            <h2 className="text-2xl font-bold mb-2">Your Total Monthly Payment</h2>
            <div className="text-4xl font-bold mb-2">
              €{uswCalculation?.totalCharge?.toFixed(2) || "0.00"}
            </div>
            <p className="text-emerald-100 text-sm mb-2">
              Covers all {uswCalculation?.breakdown.subscriptionCount || 0} subscriptions + {uswCalculation?.isPremium ? "no fees (Premium)" : "small convenience fee"}
            </p>
            <p className="text-emerald-200 text-xs mb-6">
              One payment to us • We handle everything else
            </p>

            {uswCalculation?.canRun ? (
              <Button
                onClick={() => setShowRunModal(true)}
                className="bg-white text-emerald-600 hover:bg-emerald-50 px-8 py-3 text-lg font-semibold"
                disabled={runUSWMutation.isPending}
              >
                {runUSWMutation.isPending ? "Running USW..." : "🚀 Run USW Now"}
              </Button>
            ) : (
              <div className="bg-white/20 rounded-xl p-4">
                <p className="text-sm mb-2">USW currently unavailable</p>
                <Link href="/analytics">
                  <Button className="bg-white text-emerald-600 hover:bg-emerald-50">
                    Upgrade to Premium
                  </Button>
                </Link>
              </div>
            )}
          </div>
        </div>

        {/* Payment Breakdown */}
        <Card className="glass-effect p-6 border-0 mb-8">
          <h3 className="font-bold text-xl mb-6 text-gray-800 text-center">Payment Breakdown</h3>
          <div className="space-y-4">
            <div className="flex justify-between items-center text-lg">
              <span className="text-gray-700">Subscription Total:</span>
              <span className="font-semibold">€{uswCalculation?.subscriptionTotal?.toFixed(2) || "0.00"}</span>
            </div>

            <div className="flex justify-between items-center text-lg">
              <span className="text-gray-700">Mulah Fees:</span>
              <span className="font-semibold">
                {uswCalculation?.isPremium ? (
                  <span>
