@layer base {
  * {
    @apply border-border;
  }

  body {
    @apply bg-background text-foreground;
    font-family: 'Inter', system-ui, sans-serif;
  }
}

@layer utilities {
  .mulah-teal {
    color: var(--mulah-teal);
  }

  .mulah-gold {
    color: var(--mulah-gold);
  }

  .mulah-light-teal {
    color: var(--mulah-light-teal);
  }

  .bg-mulah-teal {
    background-color: var(--mulah-teal);
  }

  .bg-mulah-gold {
    background-color: var(--mulah-gold);
  }

  .bg-mulah-light-teal {
    background-color: var(--mulah-light-teal);
  }

  .border-mulah-teal {
    border-color: var(--mulah-teal);
  }

  .border-mulah-gold {
    border-color: var(--mulah-gold);
  }

  .text-mulah-teal {
    color: var(--mulah-teal);
  }

  .text-mulah-gold {
    color: var(--mulah-gold);
  }

  .text-mulah-light-teal {
    color: var(--mulah-light-teal);
  }

  .text-mulah-gray {
    color: var(--mulah-gray);
  }

  .hide-scrollbar {
    -ms-overflow-style: none;
    scrollbar-width: none;
  }

  .hide-scrollbar::-webkit-scrollbar {
    display: none;
  }

  .glass-effect {
    background: rgba(255, 255, 255, 0.1);
    backdrop-filter: blur(10px);
    border: 1px solid rgba(255, 255, 255, 0.2);
  }

  .card-shadow {
    box-shadow: 0 4px 20px rgba(0, 0, 0, 0.08);
  }

  .mobile-safe {
    padding-bottom: env(safe-area-inset-bottom);
  }
}

@layer components {
  .mobile-container {
    @apply w-full max-w-md mx-auto bg-background min-h-screen relative overflow-hidden;
    max-height: 100vh;
    padding: 0;
    margin: 0 auto;
  }

  .gradient-header {
    background: linear-gradient(to bottom right, hsl(163, 67%, 22%), hsl(172, 74%, 56%));
  }

  .gradient-card {
    background: linear-gradient(-45deg, #667eea, #764ba2, #f093fb, #f5576c);
    background-size: 400% 400%;
    animation: gradient 6s ease infinite;
  }

  .glass-effect {
    backdrop-filter: blur(20px);
    background: rgba(255, 255, 255, 0.25);
    border: 1px solid rgba(255, 255, 255, 0.18);
  }

  .card-hover {
    transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  }

  .card-hover:hover {
    transform: translateY(-8px) scale(1.02);
    box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.15);
  }

  .modern-shadow {
    box-shadow: 0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04);
  }

  .premium-gradient {
    background: linear-gradient(135deg, #10B981 0%, #059669 100%);
  }

  .success-gradient {
    background: linear-gradient(135deg, #10B981 0%, #38ef7d 100%);
  }

  .warning-gradient {
    background: linear-gradient(135deg, #f093fb 0%, #f5576c 100%);
  }

  .info-gradient {
    background: linear-gradient(135deg, #10B981 0%, #0F172A 100%);
  }

  .mulah-primary {
    background: linear-gradient(135deg, #10B981 0%, #0F172A 100%);
  }

  .subscription-card {
    @apply bg-card rounded-xl p-4 card-shadow border border-border card-hover;
  }

  .action-button {
    @apply flex flex-col items-center p-4 rounded-xl transition-transform active:scale-95;
  }

  .icon-circle {
    @apply w-12 h-12 rounded-full flex items-center justify-center mb-2;
  }

  .mobile-header {
    @apply flex items-center justify-between p-4 bg-white dark:bg-gray-900 border-b sticky top-0 z-10;
  }

  .mobile-content {
    @apply flex-1 overflow-y-auto px-4 pb-20;
    height: calc(100vh - 64px);
  }

  .compact-card {
    @apply bg-white dark:bg-gray-800 rounded-lg p-3 shadow-sm border border-gray-200 dark:border-gray-700;
  }

  .service-grid {
    @apply grid grid-cols-2 gap-3;
  }

  .service-item {
    @apply rounded-lg border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 active:scale-95 transition-transform;
  }

  .category-grid {
    @apply grid grid-cols-2 gap-3;
  }

  .category-grid .col-span-2 {
    grid-column: span 2;
  }

  .category-item {
    @apply rounded-lg border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 cursor-pointer hover:shadow-md active:scale-95 transition-all;
  }
}

/* PWA specific styles */
@media (display-mode: standalone) {
  body {
    padding-top: env(safe-area-inset-top);
  }
}

/* Animation keyframes */
@keyframes slideUp {
  from { 
    transform: translateY(20px); 
    opacity: 0; 
  }
  to { 
    transform: translateY(0); 
    opacity: 1; 
  }
}

@keyframes fadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}

@keyframes bounceGentle {
  0%, 20%, 50%, 80%, 100% { transform: translateY(0); }
  40% { transform: translateY(-5px); }
  60% { transform: translateY(-3px); }
}

@keyframes pulseGlow {
  0%, 100% { 
    box-shadow: 0 0 20px rgba(245, 158, 11, 0.3); 
  }
  50% { 
    box-shadow: 0 0 30px rgba(245, 158, 11, 0.6); 
  }
}

.animate-slide-up {
  animation: slideUp 0.3s ease-out;
}

.animate-fade-in {
  animation: fadeIn 0.3s ease-out;
}

.animate-bounce-gentle {
  animation: bounceGentle 0.6s ease-out;
}

.animate-pulse-glow {
  animation: pulseGlow 2s infinite;
}

/* USW First-Run Celebration Animations */
@keyframes confetti {
  0% {
    transform: translateY(-10vh) rotate(0deg);
    opacity: 1;
  }
  100% {
    transform: translateY(110vh) rotate(720deg);
    opacity: 0;
  }
}

@keyframes celebration-pop {
  0% {
    transform: scale(0.5);
    opacity: 0;
  }
  50% {
    transform: scale(1.1);
  }
  100% {
    transform: scale(1);
    opacity: 1;
  }
}

.animate-confetti {
  animation: confetti 4s ease-in-out forwards;
}

.animate-celebration-pop {
  animation: celebration-pop 0.5s ease-out forwards;
}

