client/src/pages/AddSubscription.tsx.content:
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { useToast } from "@/hooks/use-toast";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { insertSubscriptionSchema, type InsertSubscription } from "@shared/schema";
import { SUBSCRIPTION_SERVICES, SUBSCRIPTION_CATEGORIES, type SubscriptionService, type ServicePlan } from "@shared/services";
import { useMutation } from "@tanstack/react-query";
import { useState } from "react";
import { useLocation } from "wouter";
import { zodResolver } from "@hookform/resolvers/zod";
import { useForm } from "react-hook-form";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { isUnauthorizedError } from "@/lib/authUtils";
import { ArrowLeft, Check, Search, Plus, X } from "lucide-react";

export default function AddSubscription() {
  const [, setLocation] = useLocation();
  const { toast } = useToast();
  const [searchQuery, setSearchQuery] = useState("");
  const [selectedService, setSelectedService] = useState<SubscriptionService | null>(null);
  const [selectedPlan, setSelectedPlan] = useState<ServicePlan | null>(null);
  const [showCustomForm, setShowCustomForm] = useState(false);
  const [showConfirmation, setShowConfirmation] = useState(false);
  const [currentStep, setCurrentStep] = useState<'category' | 'service' | 'plan' | 'custom'>('category');

  const form = useForm({
    resolver: zodResolver(insertSubscriptionSchema.extend({
      nextBillingDate: insertSubscriptionSchema.shape.nextBillingDate.transform(val => new Date(val))
    })),
    defaultValues: {
      name: "",
      cost: "",
      billingCycle: "monthly",
      category: "other",
      description: "",
      nextBillingDate: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000),
      currency: "EUR",
      iconColor: "#1B5A52",
      iconName: "fa-star",
      isActive: true,
    },
  });

  const mutation = useMutation({
    mutationFn: async (data: InsertSubscription) => {
      return apiRequest("POST", "/api/subscriptions", data);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/subscriptions"] });
      queryClient.invalidateQueries({ queryKey: ["/api/analytics/monthly"] });
      queryClient.invalidateQueries({ queryKey: ["/api/analytics/annual"] });

      toast({
        title: "Success! 🎉",
        description: "Subscription added successfully",
      });
      setLocation("/");
    },
    onError: (error) => {
      if (isUnauthorizedError(error)) {
        toast({
          title: "Unauthorized",
          description: "You are logged out. Logging in again...",
          variant: "destructive",
        });
        setTimeout(() => {
          window.location.href = "/api/login";
        }, 500);
        return;
      }

      toast({
        title: "Error",
        description: "Failed to add subscription. Please try again.",
        variant: "destructive",
      });
    },
  });

  const handleConfirmSubscription = async () => {
    const formData = form.getValues();
    await mutation.mutateAsync(formData);
    setShowConfirmation(false);
  };

  const handleServiceSelect = (service: SubscriptionService) => {
    setSelectedService(service);
    if (service.plans.length === 1) {
      handlePlanSelect(service.plans[0]);
    } else {
      setCurrentStep('plan');
    }
  };

  const handlePlanSelect = (plan: ServicePlan) => {
    if (!selectedService) return;

    setSelectedPlan(plan);

    // Auto-populate form
    form.setValue("name", selectedService.name);
    form.setValue("cost", plan.price.toString());
    form.setValue("billingCycle", plan.billingCycle);
    form.setValue("category", selectedService.category);
    form.setValue("description", plan.name);
    form.setValue("iconColor", selectedService.color);
    form.setValue("iconName", selectedService.icon);

    setShowConfirmation(true);
  };

  const handleBackButton = () => {
    if (currentStep === 'service') {
      setCurrentStep('category');
      setSelectedService(null);
    } else if (currentStep === 'plan') {
      setCurrentStep('service');
      setSelectedPlan(null);
    } else if (currentStep === 'custom') {
      setCurrentStep('category');
      setShowCustomForm(false);
    } else {
      setLocation('/');
    }
  };

  const filteredServices = SUBSCRIPTION_SERVICES.filter(service =>
    service.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
    service.category.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const getServicesForCategory = (categoryId: string) => {
    return filteredServices.filter(service => service.category === categoryId);
  };

  return (
    <div className="mobile-container">
      {/* Mobile Header */}
      <div className="mobile-header">
        <Button variant="ghost" size="sm" onClick={handleBackButton} className="p-2">
          <ArrowLeft className="h-5 w-5" />
        </Button>
        <h1 className="text-lg font-semibold">
          {currentStep === 'category' && 'Add Subscription'}
          {currentStep === 'service' && 'Choose Service'}
          {currentStep === 'plan' && 'Select Plan'}
          {currentStep === 'custom' && 'Custom Service'}
        </h1>
        <div className="w-9" /> {/* Spacer */}
      </div>

      {/* Mobile Content */}
      <div className="mobile-content space-y-4">
        {/* Search Bar (on category and service steps) */}
        {(currentStep === 'category' || currentStep === 'service') && (
          <div className="relative">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-gray-400" />
            <Input
              placeholder="Search services..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="pl-10 h-12"
            />
          </div>
        )}

        {/* Step 1: Categories */}
        {currentStep === 'category' && (
          <div className="space-y-4">
            <div className="category-grid">
              {SUBSCRIPTION_CATEGORIES.map((category) => {
                const services = getServicesForCategory(category.id);
                if (services.length === 0) return null;

                return (
                  <div 
                    key={category.id} 
                    className="category-item"
                    onClick={() => {
                      setCurrentStep('service');
                      setSearchQuery(category.name);
                    }}
                  >
                    <div className="p-4 text-center">
                      <div className="text-2xl mb-2">{category.icon}</div>
                      <h3 className="font-medium text-sm">{category.name}</h3>
                      <p className="text-xs text-gray-500">{services.length} services</p>
                    </div>
                  </div>
                );
              })}
            </div>

            {/* Quick Custom Option */}
            <div 
              className="category-item col-span-2"
              onClick={() => {
                setCurrentStep('custom');
                setShowCustomForm(true);
              }}
            >
              <div className="p-4 text-center">
                <div className="w-8 h-8 bg-gray-100 dark:bg-gray-700 rounded-full flex items-center justify-center mx-auto mb-2">
                  <Plus className="h-4 w-4" />
                </div>
                <h3 className="font-medium text-sm">Custom Service</h3>
                <p className="text-xs text-gray-500">Add manually</p>
              </div>
            </div>
          </div>
        )}

        {/* Step 2: Services */}
        {currentStep === 'service' && (
          <div className="service-grid">
            {filteredServices.map((service) => (
              <div 
                key={service.id} 
                className="service-item cursor-pointer hover:shadow-md"
                onClick={() => handleServiceSelect(service)}
              >
                <div className="p-4 text-center">
                  <div 
                    className="w-10 h-10 rounded-lg flex items-center justify-center mx-auto mb-2 text-white text-sm"
                    style={{ backgroundColor: service.color }}
                  >
                    <i className={service.icon}></i>
                  </div>
                  <h3 className="font-medium text-sm">{service.name}</h3>
                  <p className="text-xs text-gray-500">
                    {service.plans.length} plan{service.plans.length !== 1 ? 's' : ''}
                  </p>
                </div>
              </div>
            ))}
          </div>
        )}

        {/* Step 3: Plans */}
        {currentStep === 'plan' && selectedService && (
          <div className="space-y-3">
            <div className="text-center mb-4">
              <div 
                className="w-16 h-16 rounded-xl flex items-center justify-center mx-auto mb-3 text-white text-xl"
                style={{ backgroundColor: selectedService.color }}
              >
                <i className={selectedService.icon}></i>
              </div>
              <h2 className="text-lg font-semibold">{selectedService.name}</h2>
              <p className="text-sm text-gray-500">{selectedService.description}</p>
            </div>

            {selectedService.plans.map((plan) => (
              <div 
                key={plan.id} 
                className="compact-card cursor-pointer hover:shadow-md active:scale-95 transition-transform"
                onClick={() => handlePlanSelect(plan)}
              >
                <div className="flex justify-between items-center">
                  <div>
                    <h3 className="font-medium">{plan.name}</h3>
                    <p className="text-sm text-gray-500">
                      €{plan.price}/{plan.billingCycle === 'monthly' ? 'month' : plan.billingCycle === 'yearly' ? 'year' : 'week'}
                    </p>
                  </div>
                  {plan.popular && (
                    <Badge variant="secondary" className="bg-green-100 text-green-800">
                      Popular
                    </Badge>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}

        {/* Step 4: Custom Form */}
        {currentStep === 'custom' && showCustomForm && (
          <Form {...form}>
            <form onSubmit={form.handleSubmit((data) => mutation.mutate(data))} className="space-y-4">
              <FormField
                control={form.control}
                name="name"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Service Name</FormLabel>
                    <FormControl>
                      <Input {...field} placeholder="Netflix, Spotify, etc." />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <div className="grid grid-cols-2 gap-4">
                <FormField
                  control={form.control}
                  name="cost"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Cost</FormLabel>
                      <FormControl>
                        <Input {...field} type="number" step="0.01" placeholder="9.99" />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="billingCycle"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Billing</FormLabel>
                      <Select onValueChange={field.onChange} defaultValue={field.value}>
                        <FormControl>
                          <SelectTrigger>
                            <SelectValue />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          <SelectItem value="weekly">Weekly</SelectItem>
                          <SelectItem value="monthly">Monthly</SelectItem>
                          <SelectItem value="yearly">Yearly</SelectItem>
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              </div>

              <FormField
                control={form.control}
                name="category"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Category</FormLabel>
                    <Select onValueChange={field.onChange} defaultValue={field.value}>
                      <FormControl>
                        <SelectTrigger>
                          <SelectValue />
                        </SelectTrigger>
                      </FormControl>
                      <SelectContent>
                        {SUBSCRIPTION_CATEGORIES.map((category) => (
                          <SelectItem key={category.id} value={category.id}>
                            {category.icon} {category.name}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <Button 
                type="submit" 
                className="w-full h-12 bg-green-600 hover:bg-green-700"
                disabled={mutation.isPending}
              >
                {mutation.isPending ? "Adding..." : "Add Subscription"}
              </Button>
            </form>
          </Form>
        )}
      </div>

      {/* Confirmation Dialog */}
      <Dialog open={showConfirmation} onOpenChange={setShowConfirmation}>
        <DialogContent className="max-w-sm mx-auto">
          <DialogHeader>
            <DialogTitle className="text-center">Confirm Subscription</DialogTitle>
          </DialogHeader>

          {selectedService && selectedPlan && (
            <div className="space-y-4">
              <div className="text-center">
                <div 
                  className="w-16 h-16 rounded-xl flex items-center justify-center mx-auto mb-3 text-white text-xl"
                  style={{ backgroundColor: selectedService.color }}
                >
                  <i className={selectedService.icon}></i>
                </div>
                <h3 className="text-lg font-semibold">{selectedService.name}</h3>
                <p className="text-sm text-gray-500">{selectedPlan.name}</p>
                <p className="text-xl font-bold text-green-600 mt-2">
                  €{selectedPlan.price}/{selectedPlan.billingCycle === 'monthly' ? 'mo' : selectedPlan.billingCycle === 'yearly' ? 'yr' : 'wk'}
                </p>
              </div>

              <div className="flex gap-3">
                <Button 
                  variant="outline" 
                  onClick={() => setShowConfirmation(false)}
                  className="flex-1"
                >
                  Cancel
                </Button>
                <Button 
                  onClick={handleConfirmSubscription}
                  className="flex-1 bg-green-600 hover:bg-green-700"
                  disabled={mutation.isPending}
                >
                  {mutation.isPending ? "Adding..." : "Confirm"}
                </Button>
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
}

