        .filter((event: any) => event.type === 'api_call' && event.data?.responseTime)
        .slice(-20)
        .map((event: any) => ({
          time: new Date(event.timestamp).toLocaleTimeString(),
          responseTime: event.data.responseTime,
          status: event.data.statusCode
