            <div className="text-xs text-gray-400">Slow</div>
          </div>
          <div>
            <div className="text-red-400 text-lg font-bold">
              {performanceData.filter(d => d.responseTime >= 1000).length}
            </div>
            <div className="text-xs text-gray-400">Critical</div>
