import { useEffect } from "react";
import { Link } from "wouter";
import MobileNavigation from "@/components/MobileNavigation";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { useAuth } from "@/hooks/useAuth";
import { useToast } from "@/hooks/use-toast";
import ContextualHelp from "@/components/ContextualHelp";
import { BottomNavigation } from "@/components/ui/bottom-navigation";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { apiRequest } from "@/lib/queryClient";
import type { Subscription } from "@shared/schema";
import { Plus, TrendingUp, Calendar, Euro, Zap, CreditCard, LogOut } from "lucide-react";

export default function Dashboard() {
  const { user, isAuthenticated, isLoading: authLoading } = useAuth();
  const { toast } = useToast();
  const queryClient = useQueryClient();

  // Redirect to home if not authenticated
  useEffect(() => {
    if (!authLoading && !isAuthenticated) {
      toast({
        title: "Unauthorized",
        description: "You are logged out. Logging in again...",
        variant: "destructive",
      });
      setTimeout(() => {
        window.location.href = "/api/login";
      }, 500);
      return;
    }
  }, [isAuthenticated, authLoading, toast]);

  const { data: subscriptions, isLoading: subscriptionsLoading } = useQuery<Subscription[]>({
    queryKey: ["/api/subscriptions"],
    enabled: isAuthenticated,
  });

  const { data: monthlyAnalytics } = useQuery({
    queryKey: ["/api/analytics/monthly"],
    enabled: isAuthenticated,
  });

  const { data: annualAnalytics } = useQuery({
    queryKey: ["/api/analytics/annual"],
    enabled: isAuthenticated,
  });

  const { data: monthlyDueData } = useQuery({
    queryKey: ["/api/analytics/monthly-due"],
    enabled: isAuthenticated,
  });

  const demoMutation = useMutation({
    mutationFn: async () => {
      await apiRequest("POST", "/api/demo/populate", {});
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/subscriptions"] });
      queryClient.invalidateQueries({ queryKey: ["/api/analytics/monthly"] });
      queryClient.invalidateQueries({ queryKey: ["/api/analytics/annual"] });
      queryClient.invalidateQueries({ queryKey: ["/api/analytics/monthly-due"] });
      toast({
        title: "Demo data added!",
        description: "5 sample subscriptions have been added to your account.",
      });
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: "Failed to add demo data. Please try again.",
        variant: "destructive",
      });
    },
  });

  if (authLoading) {
    return <div className="mobile-container flex items-center justify-center min-h-screen">Loading...</div>;
  }

  if (!isAuthenticated) {
    return null;
  }

  const totalMonthly = (monthlyAnalytics as any)?.total || 0;
  const totalAnnual = (annualAnalytics as any)?.total || 0;
  const subscriptionCount = subscriptions?.length || 0;
  const monthlyDueCount = (monthlyDueData as any)?.count || 0;

  return (
    <>
      <MobileNavigation />
      <div className="mobile-container pb-20 md:pb-0">
      {/* Mobile Header */}
      <div className="mobile-header">
        <div>
          <h1 className="text-lg font-bold">Mulah</h1>
          <p className="text-xs text-gray-500">Financial Control</p>
        </div>
        <div className="flex items-center space-x-2">
          <Button 
            size="sm" 
            variant="ghost"
            className="h-8 w-8 p-0 text-gray-500 hover:text-red-600 hover:bg-red-50"
            onClick={() => window.location.href = '/api/logout'}
            title="Sign Out"
          >
            <LogOut className="h-4 w-4" />
          </Button>
          <Link href="/add" className="inline-block">
            <Button size="sm" className="h-8 w-8 p-0 bg-green-600 hover:bg-green-700">
              <Plus className="h-4 w-4" />
            </Button>
          </Link>
        </div>
      </div>

      {/* Mobile Content */}
      <div className="mobile-content space-y-4">
        {/* Quick Stats */}
        <div className="grid grid-cols-2 gap-3">
          <Card className="compact-card">
            <CardContent className="p-3">
              <div className="flex items-center space-x-2">
                <div className="p-2 bg-green-100 rounded-lg">
                  <Euro className="h-4 w-4 text-green-600" />
                </div>
                <div>
                  <p className="text-xs text-gray-500">This Month</p>
                  <p className="text-lg font-bold">€{totalMonthly.toFixed(2)}</p>
                </div>
              </div>
            </CardContent>
          </Card>

          <Card className="compact-card">
            <CardContent className="p-3">
              <div className="flex items-center space-x-2">
                <div className="p-2 bg-blue-100 rounded-lg">
                  <TrendingUp className="h-4 w-4 text-blue-600" />
                </div>
                <div>
                  <p className="text-xs text-gray-500">Due This Month</p>
                  <p className="text-lg font-bold">{monthlyDueCount}</p>
                </div>
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Quick Actions */}
        <div className="grid grid-cols-3 gap-3">
          <Link href="/usw" className="block">
            <Card className="compact-card cursor-pointer hover:shadow-md active:scale-95 transition-transform">
              <CardContent className="p-3 text-center">
                <div className="p-2 bg-purple-100 rounded-lg mx-auto w-fit mb-2">
                  <Zap className="h-4 w-4 text-purple-600" />
                </div>
                <p className="text-xs font-medium">USW</p>
              </CardContent>
            </Card>
          </Link>

          <Link href="/analytics" className="block">
            <Card className="compact-card cursor-pointer hover:shadow-md active:scale-95 transition-transform">
              <CardContent className="p-3 text-center">
                <div className="p-2 bg-orange-100 rounded-lg mx-auto w-fit mb-2">
                  <TrendingUp className="h-4 w-4 text-orange-600" />
                </div>
                <p className="text-xs font-medium">Analytics</p>
              </CardContent>
            </Card>
          </Link>

          <Link href="/cards" className="block">
            <Card className="compact-card cursor-pointer hover:shadow-md active:scale-95 transition-transform">
              <CardContent className="p-3 text-center">
                <div className="p-2 bg-indigo-100 rounded-lg mx-auto w-fit mb-2">
                  <CreditCard className="h-4 w-4 text-indigo-600" />
                </div>
                <p className="text-xs font-medium">Cards</p>
              </CardContent>
            </Card>
          </Link>
        </div>

        {/* Subscription List */}
        <div className="space-y-3">
          <div className="flex items-center justify-between">
            <div>
              <h2 className="text-lg font-semibold">Your Subscriptions</h2>
              <p className="text-xs text-gray-500">{subscriptionCount} total subscriptions</p>
            </div>
            {subscriptionCount === 0 && (
              <Button 
                onClick={() => demoMutation.mutate()}
                variant="outline" 
                size="sm"
                disabled={demoMutation.isPending}
              >
                {demoMutation.isPending ? "Adding..." : "Add Demo"}
              </Button>
            )}
          </div>

          {subscriptionsLoading ? (
            <div className="space-y-3">
              {[1, 2, 3].map((i) => (
                <Card key={i} className="compact-card">
                  <CardContent className="p-3">
                    <div className="flex items-center space-x-3">
                      <Skeleton className="h-10 w-10 rounded-lg" />
                      <div className="flex-1">
                        <Skeleton className="h-4 w-24 mb-1" />
                        <Skeleton className="h-3 w-16" />
                      </div>
                      <Skeleton className="h-4 w-12" />
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          ) : subscriptions && subscriptions.length > 0 ? (
            <div className="space-y-2">
              {subscriptions.map((subscription) => (
                <Card key={subscription.id} className="compact-card">
                  <CardContent className="p-3">
                    <div className="flex items-center space-x-3">
                      <div 
                        className="w-10 h-10 rounded-lg flex items-center justify-center text-white text-sm"
                        style={{ backgroundColor: subscription.iconColor }}
                      >
                        <i className={subscription.iconName}></i>
                      </div>
                      <div className="flex-1 min-w-0">
                        <h3 className="font-medium text-sm truncate">{subscription.name}</h3>
                        <p className="text-xs text-gray-500">
                          {subscription.billingCycle === 'monthly' ? 'Monthly' : 
                           subscription.billingCycle === 'yearly' ? 'Yearly' : 'Weekly'}
                        </p>
                      </div>
                      <div className="text-right">
                        <p className="font-semibold text-sm">€{parseFloat(subscription.cost).toFixed(2)}</p>
                        <p className="text-xs text-gray-500">
                          {new Date(subscription.nextBillingDate).toLocaleDateString('en-GB', { 
                            day: 'numeric', 
                            month: 'short' 
                          })}
                        </p>
                      </div>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          ) : (
            <Card className="compact-card">
              <CardContent className="p-6 text-center">
                <div className="p-3 bg-gray-100 rounded-full mx-auto w-fit mb-3">
                  <Plus className="h-6 w-6 text-gray-400" />
                </div>
                <h3 className="font-medium mb-2">No subscriptions yet</h3>
                <p className="text-sm text-gray-500 mb-4">
                  Start by adding your first subscription
                </p>
                <Link href="/add">
                  <Button className="w-full bg-green-600 hover:bg-green-700">
                    Add Subscription
                  </Button>
                </Link>
              </CardContent>
            </Card>
          )}
        </div>
      </div>
    </div>

    <ContextualHelp
      pageContext="dashboard"
      pageTitle="Dashboard"
      suggestedCategory="technical"
      variant="floating"
    />
    </>
  );
}

