      ];

      // Generate monthly subscription payments
      for (let month = 8; month <= 12; month++) {
        subscriptions.forEach(sub => {
          const date = new Date(2024, month - 1, sub.day);
          if (date <= endDate) {
            transactions.push({
              id: `sub_${email}_${month}_${sub.name.replace(/\s+/g, '_')}`,
