            });
          }
        });
      }

      // Continue for January 2025
      subscriptions.forEach(sub => {
        const date = new Date(2025, 0, sub.day);
        transactions.push({
          id: `sub_${email}_2025_01_${sub.name.replace(/\s+/g, '_')}`,
